<?php require __DIR__."/vendor/autoload.php"; $app = require_once __DIR__."/bootstrap/app.php"; $kernel = $app->make(Illuminate\Contracts\Console\Kernel::class); $kernel->bootstrap(); $user = App\Models\User::first(); $raw = "AABBCC"; DB::table("password_reset_tokens")->updateOrInsert(["email" => strtolower($user->email)], ["token" => hash("sha256", $raw), "created_at" => now(), "attempts" => 0]); $service = app(App\Services\Auth\PasswordResetService::class); $st = microtime(true); try { $service->resetPassword($user->email, $raw, "MismL3".rand(100,999), "127.0.0.1", "Test"); echo "Success: ".(microtime(true) - $st)."\n"; } catch (\Exception $e) { echo "Error: ".$e->getMessage(); }